#include <iostream>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    // dp0[i] = sequences of length i ending with 0
    // dp1[i] = sequences of length i ending with 1
    long long dp0 = 1, dp1 = 1;
    for (int i = 2; i <= n; i++) {
        long long new0 = dp0 + dp1;
        long long new1 = dp0;
        dp0 = new0;
        dp1 = new1;
    }

    cout << dp0 + dp1 << "\n";
    return 0;
}
